"use client";

import { useMemo, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import {
  ColumnDef,
  flexRender,
  getCoreRowModel,
  getFilteredRowModel,
  useReactTable
} from "@tanstack/react-table";
import Link from "next/link";

import { getTeams, Team } from "../../lib/api";

export default function TeamsPage() {
  const { data = [], isLoading, error } = useQuery({
    queryKey: ["teams"],
    queryFn: getTeams
  });

  const [globalFilter, setGlobalFilter] = useState("");

  const columns = useMemo<ColumnDef<Team>[]>(
    () => [
      {
        accessorKey: "name",
        header: "Team",
        cell: (info) => {
          const team = info.row.original;
          return (
            <Link href={`/teams/${team.slug}`} className="text-wave hover:underline">
              {team.name}
            </Link>
          );
        }
      },
      {
        accessorKey: "aggregates.goals_per_match",
        header: "Goals / Match",
        cell: (info) => info.getValue<number>().toFixed(2)
      },
      {
        accessorKey: "aggregates.shooting_pct",
        header: "Shooting %",
        cell: (info) => `${(info.getValue<number>() * 100).toFixed(1)}%`
      },
      {
        accessorKey: "aggregates.extra_man_pct",
        header: "Extra-man %",
        cell: (info) => `${(info.getValue<number>() * 100).toFixed(1)}%`
      }
    ],
    []
  );

  const table = useReactTable({
    data,
    columns,
    state: { globalFilter },
    onGlobalFilterChange: setGlobalFilter,
    getCoreRowModel: getCoreRowModel(),
    getFilteredRowModel: getFilteredRowModel()
  });

  return (
    <section className="grid gap-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-semibold">Teams</h2>
          <p className="text-slate">League-wide efficiency snapshots and form metrics.</p>
        </div>
        <input
          className="rounded-full border border-slate/40 px-4 py-2 text-sm bg-white"
          placeholder="Search team"
          value={globalFilter}
          onChange={(event) => setGlobalFilter(event.target.value)}
        />
      </div>

      <div className="rounded-3xl bg-white/80 shadow-sm border border-white overflow-hidden">
        {isLoading ? (
          <p className="p-6 text-slate">Loading teams...</p>
        ) : error ? (
          <p className="p-6 text-red-500">Failed to load teams.</p>
        ) : (
          <table className="w-full text-sm">
            <thead className="bg-slate/5 text-slate">
              {table.getHeaderGroups().map((headerGroup) => (
                <tr key={headerGroup.id}>
                  {headerGroup.headers.map((header) => (
                    <th key={header.id} className="text-left px-6 py-3 font-medium">
                      {header.isPlaceholder
                        ? null
                        : flexRender(header.column.columnDef.header, header.getContext())}
                    </th>
                  ))}
                </tr>
              ))}
            </thead>
            <tbody>
              {table.getRowModel().rows.map((row) => (
                <tr key={row.id} className="border-t border-slate/10">
                  {row.getVisibleCells().map((cell) => (
                    <td key={cell.id} className="px-6 py-3">
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </section>
  );
}
