export type TeamAggregate = {
  matches: number;
  goals_per_match: number;
  shooting_pct: number;
  extra_man_pct: number;
  center_pct: number;
  counter_pct: number;
  penalty_pct: number;
  sprints_win_pct: number;
  turnovers_per_match: number;
  steals_per_match: number;
};

export type Team = {
  id: number;
  name: string;
  slug: string;
  aggregates: TeamAggregate;
};

export type TeamTrendPoint = {
  match_index: number;
  goals: number;
  shots: number;
  shooting_pct: number;
};

export type TeamTrends = {
  team_id: number;
  window: number;
  points: TeamTrendPoint[];
};

export type Player = {
  id: number;
  team_id: number | null;
  name: string;
  number: number | null;
  position: string | null;
};

export type MetaFreshness = {
  last_import: string | null;
  team_count: number;
  match_count: number;
  team_match_stat_count: number;
};

export type ScheduleOption = {
  file: string;
  date: string | null;
  counter: string;
};

const baseUrl = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

async function fetchJson<T>(path: string): Promise<T> {
  const res = await fetch(`${baseUrl}${path}`);
  if (!res.ok) {
    throw new Error(`Request failed: ${res.status}`);
  }
  return res.json() as Promise<T>;
}

export function getTeams() {
  return fetchJson<Team[]>("/teams");
}

export function getTeam(id: number) {
  return fetchJson<Team>(`/teams/${id}`);
}

export function getTeamBySlug(slug: string) {
  return fetchJson<Team>(`/teams/slug/${slug}`);
}

export function getTeamTrends(id: number, window = 5) {
  return fetchJson<TeamTrends>(`/teams/${id}/trends?window=${window}`);
}

export function getPlayers() {
  return fetchJson<Player[]>("/players");
}

export function getPlayer(id: number) {
  return fetchJson<Player>(`/players/${id}`);
}

export function compareTeams(teamA: number, teamB: number) {
  return fetchJson<{ deltas: Record<string, number>; team_a: Team; team_b: Team }>(
    `/compare?teamA=${teamA}&teamB=${teamB}`
  );
}

export function getFreshness() {
  return fetchJson<MetaFreshness>("/meta/freshness");
}

export function getOptions() {
  return fetchJson<{ schedules: ScheduleOption[] }>("/meta/options");
}
